mapper.select:
SELECT A.PRDCT_ID, A.EDOC_CD, A.ESS_YN, A.REG_DT, A.APPLCD_GBN, B.EDOC_GBN, B.EDOC_NM FROM NF_PRDCT_EDOC A, NF_EDOC_INFO B WHERE A.EDOC_CD = B.EDOC_CD AND B.EDOC_GBN = 'PDF' AND A.PRDCT_ID = #{prdctId}
AND A.EDOC_CD = #{edocCd}
AND A.APPLCD_GBN IN ( SELECT A.APPLCD_GBN FROM NF_PRDCT_EDOC A , NF_EDOC_INFO B WHERE A.PRDCT_ID = #{prdctId} AND A.EDOC_CD = B.EDOC_CD AND B.EDOC_GBN = 'PDF' AND A.APPLCD_GBN != '' GROUP BY APPLCD_GBN HAVING COUNT(APPLCD_GBN) > 1 )
